+bool VectorNode::is_vectormask_bitwise_not_pattern(Node* n) {
+  if (n->Opcode() == Op_XorVMask) {
+    return is_all_ones_vector(n->in(1)) ||
+           is_all_ones_vector(n->in(2));
+  }
+  return false;
+}

